/**
 * Indicates whether the current environment is a client or server.
 * 
 * Both isClient and isServer can be true at the same time if a game is running in peer-to-peer mode, not on a dedicated server.
 * 
 * ```ts
 * J.onGameStart(() => {
 *   if (J.net.isHost) {
 *     // logic that should only run on the host/server
 *     // ...
 *   }
 * });
 * 
 * J.onGameStart(() => {
 *   if (J.net.isClient) {
 *     // logic that should only run clients
 *     // ...
 *   }
 * });
 * ```
 * 
 * ### Networking Commands
 * 
 * #### `J.net.defineCommand<TData>(name: string) => Command<TData>`
 * - **Environment: both**
 * 
 * Defines a custom network command for sending data between clients and server. Returns a command object that can be used with send, sendToAll, and listen.
 * 
 * ```ts
 * // Define a command with TypeScript data
 * const MyCommand = J.net.defineCommand<{ value: number; message: string }>("myCommand");
 * ```
 * 
 * #### `J.net.send<TCommand>(command: TCommand, data: TCommand["_data"], target?: EntityId | EntityId[]) => void`
 * - **Environment: both**
 * 
 * Sends a command to specific targets (clients or server). If no target is specified, sends to the server.
 * 
 * ```ts
 * // Send to server from client
 * J.net.send(MyCommand, { value: 10, message: "Hello" });
 * 
 * // Send to specific player from server
 * J.net.send(MyCommand, { value: 20, message: "Response" }, playerId);
 * 
 * // Send to multiple players
 * J.net.send(MyCommand, { value: 30, message: "Broadcast" }, [playerId1, playerId2]);
 * ```
 * 
 * #### `J.net.sendToAll<TCommand>(command: TCommand, data: TCommand["_data"], except?: EntityId) => void`
 * - **Environment: both**
 * 
 * Sends a command to all clients except optionally one (usually the sender).
 * 
 * ```ts
 * // Send to all clients
 * J.net.sendToAll(MyCommand, { value: 100, message: "Everyone" });
 * 
 * // Send to all except one player
 * J.net.sendToAll(MyCommand, { value: 200, message: "Others" }, excludedPlayerId);
 * ```
 * 
 * #### `J.net.listen<TCommand>(command: TCommand, handler: (data: TCommand["_data"], playerId?: EntityId) => void) => () => void`
 * - **Environment: both**
 * 
 * Listens for a command and returns an unsubscribe function. The handler receives the data and optionally the sender's player ID.
 * 
 * ```ts
 * // Listen for a command
 * const unsubscribe = J.net.listen(MyCommand, (data, playerId) => {
 *   console.log("Received command:", data);
 *   if (playerId) {
 *     console.log("From player:", playerId);
 *   }
 * });
 * 
 * // Stop listening when done
 * unsubscribe();
 * ```
 * 
 * ## Scene Tree
*/
export const net: {
	isClient: boolean;
	isHost: boolean;
	defineCommand: <TData>(name: string) => Command<TData>;
	send: <TCommand extends Command<any>>(
		command: TCommand,
		data: TCommand["_data"],
		target?: EntityId | EntityId[],
	) => void;
	sendToAll: <TCommand extends Command<any>>(
		command: TCommand,
		data: TCommand["_data"],
		except?: EntityId,
	) => void;
	listen: <TCommand extends Command<any>>(
		command: TCommand,
		handler: (data: TCommand["_data"], playerId?: EntityId) => void,
	) => () => void;
} = impl.net;

