/**
 * - **Environment: both**
 * 
 * Layers a partial config on top of the character's current avatar.
 * 
 * 1. **Omitted = untouched.** Fields you don't pass stay as-is, at every level.
 * 2. **Components stack per slot.** `components.chest: [x]` adds `x` alongside what's already there (doesn't replace). Duplicate `id`s per slot are skipped.
 * 
 * Everything else (`rigId`, colors, face fields) simply overwrites when you pass it.
 * Animation overrides currently support `anim.idle`, `anim.run`, `anim.walk`, and `anim.crouch`; set any of them to a GLB clip name or `null` to use the default rig animation.
 * 
 * > Full replace? Use `setCharacterAvatarByConfig`.
 * 
 * ```ts
 * // Character starts with the player's base avatar (e.g. chest slot = [default_chest])
 * J.onPlayerJoin((playerId) => {
 *     J.addCharacterAvatarConfig(playerId, {
 *         hairColor: "#000000",                                                // overwrites hair
 *         face: { eyeId: "Eye_Editor.png" },                                   // overwrites just eyeId; other face fields stay
 *         components: {
 *             chest: [{ id: "aero_chest", colors: { "01": "#ffffff" } }],      // chest slot → [default_chest, aero_chest]
 *             legLeft: [{ id: "aero_legLeft", colors: { "01": "#fff333", "02": "#FFFFFF" } }],
 *             legRight: [{ id: "aero_legRight", colors: {} }],
 *         },
 *     });
 * });
 * ```
 * 
 * ```ts
 * // Zombie mode, change skin + face, components untouched
 * J.addCharacterAvatarConfig(playerId, {
 *     skinColorPrimary: "#00ff00",
 *     anim: { run: J.assets.animations.locomotion_zombie_run.id },
 *     face: { eyeId: "Eye_M_Void.png" },
 * });
 * 
 * // Change a player's locomotion style. Use J.assets.animations for autocomplete
 * // over every GLB animation clip available in the character rig.
 * J.addCharacterAvatarConfig(playerId, {
 *     anim: {
 *         idle: J.assets.animations.locomotion_happy_idle.id,
 *         run: J.assets.animations.locomotion_happy_run.id,
 *         walk: J.assets.animations.locomotion_happy_walk.id,
 *         crouch: J.assets.animations.locomotion_fight_crouch.id,
 *     },
 * });
 * 
 * // Undo all modifications, reset to the player's original avatar
 * const base = J.getPlayerBaseAvatar(playerId);
 * J.setCharacterAvatarByConfig(playerId, base);
 * ```
*/
export const addCharacterAvatarConfig: (
	entityId: EntityId,
	config: PartialCharacterAvatarConfig,
) => void = impl.addCharacterAvatarConfig;

/**
 * - **Environment: both**
 * 
 * Performs a raycast from the given origin in the specified direction for a certain distance. Returns an object with details about the hit.
 * 
 * ```ts
 * J.onGameStart(() => {
 *   const origin = [0, 0, 0]; // starting point of the ray
 *   const direction = [1, 0, 0]; // direction the ray should travel in
 *   const distance = 10; // the maximum distance the ray should travel
 *   const ignoreEntityIds = []; // optional array of entity IDs to ignore in the raycast, e.g. a player's own character
 * 
 *   const result = J.raycast(origin, direction, distance, ignoreEntityIds);
 * 
 *   console.log(
 *     "Raycast result:",
 *     result.hit,
 *     result.hitBlock,
 *     result.hitEntityId,
 *     result.hitDistance,
 *     result.hitPosition,
 *     result.hitNormal
 *   );
 * });
 * ```
*/
