/**
 * - **Environment: both**
 * 
 * Updates the physics properties of an existing prop entity. Only works on entities that are props. All properties in the object are optional.
 * 
 * ```ts
 * // spawn a prop
 * const propId = J.spawnProp("prop#ABCDE12345");
 * 
 * // make the prop dynamic and bouncy
 * J.updatePropPhysicsProperties(propId, {
 *   motionType: J.MOTION_TYPE_DYNAMIC,
 *   sensor: false,
 *   scale: 1.0,
 *   mass: 5.0,
 *   friction: 0.1,
 *   restitution: 0.8,
 *   gravityFactor: 1.0,
 * });
 * 
 * // change motion type to dynamic (affected by gravity and collisions)
 * J.updatePropPhysicsProperties(propId, { motionType: J.MOTION_TYPE_DYNAMIC });
 * 
 * // change motion type to static (not affected by gravity, no collisions, no movement)
 * J.updatePropPhysicsProperties(propId, { motionType: J.MOTION_TYPE_STATIC });
 * 
 * // change motion type to kinematic (not affected by gravity or collisions, but can be moved with velocity)
 * J.updatePropPhysicsProperties(propId, { motionType: J.MOTION_TYPE_KINEMATIC });
 * 
 * // make it a sensor (no collision) and scale it up
 * J.updatePropPhysicsProperties(propId, { sensor: true, scale: 2.0 });
 * ```
*/
export const updatePropPhysicsProperties: (
	entityId: EntityId,
	properties: {
		motionType?: MotionType;
		sensor?: boolean;
		scale?: number;
		mass?: number;
		friction?: number;
		restitution?: number;
		gravityFactor?: number;
	},
) => void = impl.updatePropPhysicsProperties;

/**
 * - **Environment: both**
 * 
 * Gets the current physics properties of a prop entity. Returns undefined if the entity doesn't exist or is not a prop. The returned object is a shallow copy that can be modified and passed to `updatePropPhysicsProperties`.
 * 
 * ```ts
 * // spawn a prop
 * const propId = J.spawnProp("prop#ABCDE12345");
 * 
 * // get current physics properties
 * const properties = J.getPropPhysicsProperties(propId);
 * if (properties) {
 *   console.log("Current properties:", properties);
 * 
 *   // modify properties and update (get -> edit -> set pattern)
 *   properties.mass *= 2; // double the mass
 *   properties.friction = 0.5; // change friction
 *   J.updatePropPhysicsProperties(propId, properties);
 * 
 *   // or just update specific properties
 *   J.updatePropPhysicsProperties(propId, { mass: properties.mass * 2 });
 * }
 * ```
*/
export const getPropPhysicsProperties: (entityId: EntityId) =>
	| {
			motionType: MotionType;
			sensor: boolean;
			scale: number;
			mass: number;
			friction: number;
			restitution: number;
			gravityFactor: number;
	  }
	| undefined = impl.getPropPhysicsProperties;

