/**
 * - **Environment: client**
 * 
 * Registers a handler for each game render. This only runs on the client side. Runs at the client's render framerate and receives the render-frame `deltaTime` and world `time`.
 * 
 * This is typically used with `J.getScreenPosition` to position UI relative to the 3D world at the same FPS as the game's rendering.
*/
export const onGameRender: (fn: (deltaTime: number, time: number) => void) => void = impl.onGameRender;

/**
 * - **Environment: client**
 * 
 * Registers a handler for drawing 2D overlay UI (HUDs, debug text, minimaps) with the canvas 2D API. The handler runs once per render frame, after the 3D scene has rendered, and receives a `CanvasRenderingContext2D` for an engine-managed 2D canvas. After all handlers have drawn, the engine composites the canvas into the main game canvas, so the overlay is part of the final visible frame and is included in screenshots and recordings of the game canvas.
 * 
 * You draw in CSS pixels: `width` / `height` are the logical canvas size, and the engine handles device pixel ratio for you — text and shapes are always rendered at native resolution, no `devicePixelRatio` handling needed. This is the same coordinate space as `getScreenPosition` (draw at its output directly) and `getPointer` (hit-test against its `x`/`y` directly).
 * 
 * The canvas is cleared by the engine at the start of every frame, so draw everything you need each frame. Registering multiple handlers is fine — they all draw into the same canvas, in registration order.
 * 
 * ```ts
 * J.onGameUiCanvas((ctx, width, height) => {
 *   ctx.fillStyle = "white";
 *   ctx.font = "24px sans-serif";
 *   ctx.fillText(`Score: ${score}`, 32, height - 32);
 * });
 * ```
*/
export const onGameUiCanvas: (
	fn: (
		ctx: CanvasRenderingContext2D,
		width: number,
		height: number,
		deltaTime: number,
		time: number,
	) => void,
) => void = impl.onGameUiCanvas;

