/**
 * - **Environment: server**
 * 
 * Gets the persistent data associated with a player. This data persists across game sessions and can be used to store player progress, preferences, or other persistent state.
 * 
 * Note that play mode and edit mode have separate persistent data storage - data saved in play mode is not accessible in edit mode and vice versa.
*/
export const getPlayerPersistentData: (playerId: EntityId) => JsonSerialisable | undefined =
	impl.getPlayerPersistentData;

/**
 * - **Environment: server**
 * 
 * Sets the persistent data associated with a player. This data persists across game sessions and can be used to store player progress, preferences, or other persistent state.
 * 
 * Note that play mode and edit mode have separate persistent data storage - data saved in play mode is not accessible in edit mode and vice versa.
 * 
 * ```ts
 * J.onPlayerJoin((playerId, data) => {
 *   // If player doesn't have anything, add 100 coins
 *   if (data === undefined) {
 *     data = { coins: 100 };
 *     J.setPlayerPersistentData(playerId, data);
 *   }
 * 
 *   J.sendChatMessage(
 *     `Player ${playerId} has joined with ${data.coins} coins`,
 *     "#00FF00",
 *   );
 * });
 * 
 * // give players 3 coins per 1 second
 * const INTERVAL = 1;
 * const COINS_PER_INTERVAL = 3;
 * 
 * let delay = INTERVAL;
 * 
 * J.onGameTick((dt) => {
 *   delay -= dt;
 * 
 *   if (delay > 0) return;
 * 
 *   delay = INTERVAL;
 * 
 *   const players = J.getAllPlayers();
 *   players.forEach((playerId) => {
 *     const data = J.getPlayerPersistentData(playerId);
 * 
 *     if (data !== undefined) {
 *       data.coins += COINS_PER_INTERVAL;
 *       J.setPlayerPersistentData(playerId, data);
 *       J.sendChatMessage(`You have ${data.coins} coins`, "#00FF00", [playerId]);
 *     }
 *   });
 * });
 * ```
*/
export const setPlayerPersistentData: (playerId: EntityId, data: JsonSerialisable) => void =
	impl.setPlayerPersistentData;

